private List<UsageEvent> fetchAllUsage(String customerId) throws IOException {
    List<UsageEvent> all = new ArrayList<>();
    String nextPage = null;
    do {
        String url = BASE_URL + customerId;
        if (nextPage != null) url += "?page=" + nextPage;
        Response response = client.newCall(new Request.Builder().url(url).build()).execute();
        UsagePage page = gson.fromJson(response.body().string(), UsagePage.class);
        all.addAll(page.events());
        nextPage = page.nextPageToken();
    } while (nextPage != null);
    return all;
}
